const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const files = (raw.match(/^FILE:.*$/gm) || []).map(s => s.slice(5));
const healthy = files.length > 0;
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: '🧠 Security Memory Monthly' } },
  { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Files Found:* ${files.length}` } ] },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: files.length ? `*Memory files*\n• ${files.slice(0, 10).join('\n• ')}` : 'No memory files found.' } }
];
return [{ json: { checkedAt: now, healthy, status: healthy ? 'OK' : 'Missing Memory Files', slackText: `🧠 Security memory monthly: ${healthy ? 'OK' : 'Missing memory files'}`, slackBlocks: blocks } }];
